370→    /// Loads user display name and photo from UserDefaults or Firebase Auth.
371→    /// On app launch, syncs Firebase Auth user data to UserDefaults if not already cached.
372→    /// Always refreshes from Firebase to ensure fresh data.
373→    private func loadUserInfo() async {
374→        // First, try to load from UserDefaults (fast path for immediate display)
375→        let cachedName = UserDefaults.standard.string(forKey: "socialUserDisplayName")
376→        let cachedPhotoURLString = UserDefaults.standard.string(forKey: "socialUserPhotoURL")
377→
378→        // Set cached values immediately for fast UI update
379→        if let name = cachedName, !name.isEmpty {
380→            userName = name
381→            #if DEBUG
382→            print("[Home] 👤 Loaded cached name: \(name)")
383→            #endif
384→        }
385→        if let urlString = cachedPhotoURLString, let url = URL(string: urlString) {
386→            userPhotoURL = url
387→            #if DEBUG
388→            print("[Home] 🖼️ Loaded cached photo URL: \(urlString)")
389→            #endif
390→        }
391→
392→        // Always try to refresh from Firebase to get latest data (photo might be updated)
393→        guard let authRepo = resolver.resolve(AuthenticationRepository.self) else {
394→            #if DEBUG
395→            print("[Home] ⚠️ AuthenticationRepository not available")
396→            #endif
397→            return
398→        }
399→
400→        do {
401→            if let currentUser = try await authRepo.currentUser() {
402→                // Update local state with fresh data from Firebase
403→                let newName = currentUser.displayName
404→                let newPhotoURL = currentUser.photoURL
405→
406→                // Only update if we got valid data (displayName is never empty from Firebase)
407→                if !newName.isEmpty && newName != "User" {
408→                    userName = newName
409→                    UserDefaults.standard.set(newName, forKey: "socialUserDisplayName")
410→                } else if userName == nil || userName?.isEmpty == true {
411→                    // Fallback: use Firebase displayName even if "User"
412→                    userName = newName
413→                    UserDefaults.standard.set(newName, forKey: "socialUserDisplayName")
414→                }
415→
416→                if let photoURL = newPhotoURL {
417→                    userPhotoURL = photoURL
418→                    UserDefaults.standard.set(photoURL.absoluteString, forKey: "socialUserPhotoURL")
419→                }
420→
421→                #if DEBUG
422→                print("[Home] ✅ User session loaded from Firebase:")
423→                print("[Home]    Name: \(newName)")
424→                print("[Home]    Photo: \(newPhotoURL?.absoluteString ?? "nil")")
425→                print("[Home]    GroupId: \(currentUser.currentGroupId ?? "nil")")
426→                #endif
427→            } else {
428→                #if DEBUG
429→                print("[Home] ℹ️ No authenticated user found in Firebase")
430→                #endif
431→            }
432→        } catch {
433→            #if DEBUG
434→            print("[Home] ❌ Failed to fetch current user from Firebase: \(error)")
435→            #endif
436→            // Keep using cached values if available
437→        }
438→    }
