478→    /// Generates a workout plan using the provided DailyCheckIn (live inputs from Home).
479→    /// This is the PRIMARY method for workout generation - uses inputs directly from the UI.
480→    func generateWorkoutWithCheckIn(_ checkIn: DailyCheckIn) async throws -> WorkoutPlan {
481→        guard
482→            let profileRepo = resolver.resolve(UserProfileRepository.self),
483→            let blocksRepo = resolver.resolve(WorkoutBlocksRepository.self),
484→            let composer = resolver.resolve(WorkoutPlanComposing.self)
485→        else {
486→            throw DomainError.repositoryFailure(reason: "Dependências para gerar o treino não estão configuradas.")
487→        }
488→
489→        guard let profile = try await profileRepo.loadProfile() else {
490→            throw DomainError.profileNotFound
