    var dayOfWeek: Int?
}

// MARK: - Trainer Workout Schedule Type

/// Type of schedule for trainer workouts.
enum TrainerWorkoutScheduleType: String, Sendable, CaseIterable, Codable {
    /// One-time scheduled workout.
    case once

    /// Recurring workout.
    case recurring

    /// Weekly scheduled workout.
    case weekly
}

