440→                            Image(systemName: "square.and.arrow.up")
441→                        }
442→                    }
443→                }
444→            }
445→        }
446→        .task {
447→            await loadPDF()
448→        }
449→    }
450→
451→    private func loadPDF() async {
452→        isLoading = true
453→        errorMessage = nil
454→        defer { isLoading = false }
455→
456→        do {
457→            let (data, _) = try await URLSession.shared.data(from: url)
458→            let tempDir = FileManager.default.temporaryDirectory
459→            let fileURL = tempDir.appendingPathComponent("\(UUID().uuidString).pdf")
460→            try data.write(to: fileURL)
461→            localURL = fileURL
462→        } catch {
463→            errorMessage = error.localizedDescription
464→        }
465→    }
466→}
